import ReactDOM from 'react-dom';
import { PopupBaseProvider } from '@salutejs/plasma-web';
import { App } from './App';
ReactDOM.render(
    <PopupBaseProvider>
        <App />
    </PopupBaseProvider>,
    document.getElementById('root')
);

import React, { useRef } from 'react';
import styled, { css } from 'styled-components';
import { IconDone } from '@salutejs/plasma-icons';
import { surfaceSolid03 } from '@salutejs/plasma-tokens-web';
import { SSRProvider, H3, Button, Drawer, DrawerHeader, DrawerContent, DrawerFooter, PopupBaseProvider } from  '@salutejs/plasma-web';
export function App() {
    const [isOpenA, setIsOpenA] = React.useState(false);
    const [isOpenB, setIsOpenB] = React.useState(false);
    const ref = useRef();
    return (
        <SSRProvider>
            <PopupBaseProvider>
                <div style={{height: "500px"}}>
                    <div style={{ display: "flex", flexDirection: "column" }}>
                        <Button
                            text="Открыть в document"
                            onClick={() => setIsOpenA(true)}
                            style={{
                                marginTop: "1rem",
                                width: "15rem"
                            }}
                        />
                        <Button
                            text="Открыть во Frame"
                            onClick={() => setIsOpenB(true)}
                            style={{
                                marginTop: "1rem",
                                width: "15rem"
                            }}
                        />
                    </div>
                    <Drawer
                        id="drawerA"
                        opened={isOpenA}
                        onClose={() => setIsOpenA(false)}
                        placement="right"
                        withBlur={false}
                        closeOnEsc={true}
                        closeOnOverlayClick={true}
                        asModal={true}
                        width="25vw"
                        height="100vh"
                    >
                            <DrawerHeader
                                hasClose={true}
                                closePlacement="right"
                                actions={(
                                    <Button size="s" view="clear" style={{
                                        position: "relative",
                                        width: "1.5rem",
                                        height: "1.5rem"
                                    }}>
                                        <IconDone size="s" />
                                    </Button>
                                )}
                                onClose={() => setIsOpenA(false)}
                            >
                                <H3>Header</H3>
                            </DrawerHeader>
                            <DrawerContent>Content</DrawerContent>
                            <DrawerFooter>
                                <H3>Footer</H3>
                            </DrawerFooter>
                        </Drawer>
                    <div
                        ref={ref}
                        style={{
                            marginTop: "1rem",
                            width: "400px",
                            height: "500px",
                            background: surfaceSolid03,
                            position: "absolute",
                            display: "flex",
                            alignItems: "flex-start",
                            justifyContent: "center",
                            padding: "1rem",
                            bottom: 0,
                            right: 0
                        }}
                    >
                        <>Frame</>
                    </div>
                    <Drawer
                        id="drawerB"
                        opened={isOpenB}
                        onClose={() => setIsOpenB(false)}
                        placement="right"
                        asModal={false}
                        frame={ref}
                        width="250px"
                        height="100%"
                    >
                            <DrawerHeader
                                hasClose={true}
                                closePlacement="right"
                                actions={(
                                    <Button size="s" view="clear" style={{
                                        position: "relative",
                                        width: "1.5rem",
                                        height: "1.5rem"
                                    }}>
                                        <IconDone size="s" />
                                    </Button>
                                )}
                                onClose={() => setIsOpenB(false)}
                            >
                                <H3>Header</H3>
                            </DrawerHeader>
                            <DrawerContent>Content</DrawerContent>
                            <DrawerFooter>
                                <H3>Footer</H3>
                            </DrawerFooter>
</Drawer>
                </div>
            </PopupBaseProvider>
        </SSRProvider>
    );
}

import React from 'react';
import { IconDone } from '@salutejs/plasma-icons';
import { createGlobalStyle } from 'styled-components';
import { SSRProvider, H3, Button, Drawer, DrawerHeader, DrawerContent, DrawerFooter, PopupProvider } from  '@salutejs/plasma-web';
export function App() {
    const [isOpenA, setIsOpenA] = React.useState(false);
    const [isOpenB, setIsOpenB] = React.useState(false);
    const animationInfo = {
        enter: 'enterAnimation 0.2s forwards',
        exit: 'exitAnimation 0.2s forwards',
    }
    const GlobalAnimations = createGlobalStyle`
        @keyframes enterAnimation {
            from {
                transform: translate(100%, -150%);
                opacity: 0;
            }
            to {
                transform: translate(0, -50%);
                opacity: 1;
            }
        }
        @keyframes exitAnimation {
            from {
                transform: translate(0, -50%);
                opacity: 1;
            }
            to {
                transform: translate(100%, -150%);
                opacity: 0;
            }
        }
    `;
    return (
        <SSRProvider>
            <GlobalAnimations />
            <PopupProvider>
                <div style={{height: "500px"}}>
                    <div style={{ display: "flex", flexDirection: "column" }}>
                        <Button
                            text="Открыть в document"
                            onClick={() => setIsOpenA(true)}
                            style={{
                                marginTop: "1rem",
                                width: "15rem"
                            }}
                        />
                    </div>
                    <Drawer
                        animationInfo={animationInfo}
                        id="drawerA"
                        opened={isOpenA}
                        onClose={() => setIsOpenA(false)}
                        placement="right"
                        withBlur={false}
                        closeOnEsc={true}
                        closeOnOverlayClick={true}
                        asModal={true}
                        width="25vw"
                        height="100vh"
                    >
                        <DrawerHeader
                            hasClose={true}
                            closePlacement="right"
                            actions={(
                                <Button size="s" view="clear" style={{
                                    position: "relative",
                                    width: "1.5rem",
                                    height: "1.5rem"
                                }}>
                                    <IconDone size="s" />
                                </Button>
                            )}
                            onClose={() => setIsOpenA(false)}
                        >
                            <H3>Header</H3>
                        </DrawerHeader>
                        <DrawerContent>Content</DrawerContent>
                        <DrawerFooter>
                            <H3>Footer</H3>
                        </DrawerFooter>
                    </Drawer>
                </div>
            </PopupProvider>
        </SSRProvider>
    );
}

